questionvariables.text:
/* Random set selection: 1..4 */
set: rand(4)+1;
c0: 3e8;

/* Dielectric parameters */
eps_r: if set=1 then 2.1 else if set=2 then 2.25 else if set=3 then 4.0 else 9.8;
Cp_pF: if set=1 then 100 else if set=2 then 80 else if set=3 then 120 else 50;
f_Hz: if set=1 then 500e6 else if set=2 then 1e9 else if set=3 then 100e6 else 500e6;

/* Capacitance in F/m */
Cp: Cp_pF * 1e-12;

/* Display-friendly values */
eps_r_disp: float(eps_r);
Cp_disp: float(Cp_pF);
f_disp_MHz: float(f_Hz / 1e6);
mat_name: if set=1 then "PTFE" else if set=2 then "polyethylene" else if set=3 then "FR-4" else "alumina";

/* --- Teacher answers --- */

/* Part (a): phase velocity v_p = c0 / sqrt(eps_r) */
ta1: float(c0 / sqrt(eps_r));

/* Part (b): distributed inductance L' = 1/(v_p^2 * C') */
ta2: float(1 / (ta1^2 * Cp));

/* Part (c): characteristic impedance Z0 = sqrt(L'/C') */
ta3: float(sqrt(ta2 / Cp));

/* Part (d): wavelength lambda = v_p / f */
ta4: float(ta1 / f_Hz);

/* Part (e): phase constant beta = 2*pi/lambda */
ta5: float(2 * %pi / ta4);

/* Display helper: L' in nH/m */
ta2_nH: float(ta2 * 1e9);

/* Part (f): Is a lossless line dispersive? No */
ta6: [[1, false, "Yes"], [2, true, "No"]];
ta6_correct: 2;

/* Part (g): If eps_r doubles, Z0 = sqrt(eps_r)/(c0*C') increases */
ta7: [[1, true, "Increases"], [2, false, "Decreases"], [3, false, "Unchanged"]];
ta7_correct: 1;
